// src/components/LeetcodeLeaderboard.js
import React, { useEffect, useState } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  ToggleButton,
  ToggleButtonGroup,
  Typography,
  Box,
} from '@mui/material';

const leetcodeUsers = ['hello', 'kmatotek', 'dude']; // update with actual usernames

const LeetcodeLeaderboard = () => {
  // 'profile' for aggregated profile data; 'contest' for contest ranking view.
  const [viewMode, setViewMode] = useState('profile');
  const [leaderboard, setLeaderboard] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  // For contest view, store the contest title (assumed same for all users)
  const [contestTitle, setContestTitle] = useState('');



  // When viewMode changes, fetch data accordingly.
  useEffect(() => {
    setLoading(true);
    setError(null);
    if (viewMode === 'profile') {
      // Fetch profile data from our backend endpoint
      fetch('http://localhost:5001/api/leetcode-leaderboard')
        .then((response) => {
          if (!response.ok) {
            throw new Error('Failed to fetch Leetcode profile data');
          }
          return response.json();
        })
        .then((data) => {
          setLeaderboard(data);
          setLoading(false);
          setContestTitle(''); // clear contest title when in profile view
        })
        .catch((err) => {
          setError(err.message);
          setLoading(false);
        });
    } else if (viewMode === 'contest') {
      // Fetch contest data for each user directly from the contest API
      Promise.all(
        leetcodeUsers.map(async (username) => {
          try {
            const res = await fetch(
              `https://alfa-leetcode-api.onrender.com/userContestRankingInfo/${username}`
            );
            if (!res.ok) {
              throw new Error(`Failed to fetch contest data for ${username}`);
            }
            const json = await res.json();
            // The API returns an object with data.userContestRankingHistory array.
            const history = json.data?.userContestRankingHistory || [];
            // Get the last contest if available.
            const lastContest = history.length > 0 ? history[history.length - 1] : null;
            return {
              username,
              // Use lastContest.ranking if available; if not, set to Infinity for sorting.
              ranking: lastContest && lastContest.ranking ? lastContest.ranking : Infinity,
              contestTitle: lastContest?.contest?.title || null,
            };
          } catch (err) {
            console.error(`Error for ${username}:`, err);
            return {
              username,
              ranking: Infinity,
              contestTitle: null,
            };
          }
        })
      )
        .then((results) => {
          // Sort ascending by ranking (lower is better). Users with ranking Infinity go last.
          results.sort((a, b) => a.ranking - b.ranking);
          setLeaderboard(results);
          // Get contest title from the first valid result, if any.
          const validTitle = results.find((r) => r.contestTitle)?.contestTitle;
          setContestTitle(validTitle || 'Contest Rankings');
          setLoading(false);
        })
        .catch((err) => {
          setError(err.message);
          setLoading(false);
        });
    }
  }, [viewMode]);

  const handleViewModeChange = (event, newMode) => {
    if (newMode !== null) {
      setViewMode(newMode);
    }
  };

  if (loading) {
    return (
      <Box sx={{ textAlign: 'center', p: 2 }}>
        <Typography>Loading Leetcode data...</Typography>
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ textAlign: 'center', p: 2, color: 'error.main' }}>
        <Typography>{error}</Typography>
      </Box>
    );
  }

  return (
    <Box sx={{ maxWidth: 900, mx: 'auto', mt: 4 }}>
      <ToggleButtonGroup
        value={viewMode}
        exclusive
        onChange={handleViewModeChange}
        aria-label="Leetcode view mode"
        sx={{
          mb: 2,
          backgroundColor: 'background.paper',
          borderRadius: 1,
        }}
      >
        <ToggleButton
          value="profile"
          aria-label="Profile view"
          sx={{
            color: 'text.primary',
            '&.Mui-selected': { backgroundColor: 'grey.800' },
          }}
        >
          Profile
        </ToggleButton>
        <ToggleButton
          value="contest"
          aria-label="Contest view"
          sx={{
            color: 'text.primary',
            '&.Mui-selected': { backgroundColor: 'grey.800' },
          }}
        >
          Contest
        </ToggleButton>
      </ToggleButtonGroup>

      {viewMode === 'contest' && contestTitle && (
        <Typography variant="h6" sx={{ textAlign: 'center', mb: 2 }}>
          {contestTitle}
        </Typography>
      )}

      <TableContainer
        component={Paper}
        sx={{
          backgroundColor: 'background.paper',
          boxShadow: 3,
          borderRadius: 2,
          mb: 4,
        }}
      >
        <Table sx={{ minWidth: 650 }} aria-label="Leetcode leaderboard table">
          <TableHead sx={{ backgroundColor: 'grey.900' }}>
            <TableRow>
              <TableCell sx={{ color: 'text.primary', fontWeight: 'bold' }}>
                Username
              </TableCell>
              {viewMode === 'profile' ? (
                <>
                  <TableCell align="right" sx={{ color: 'text.primary', fontWeight: 'bold' }}>
                    Total Solved
                  </TableCell>
                  <TableCell align="right" sx={{ color: 'text.primary', fontWeight: 'bold' }}>
                    Ranking
                  </TableCell>
                </>
              ) : (
                <TableCell align="right" sx={{ color: 'text.primary', fontWeight: 'bold' }}>
                  Contest Ranking
                </TableCell>
              )}
            </TableRow>
          </TableHead>
          <TableBody>
            {leaderboard.map((user, index) => (
              <TableRow
                key={user.username || index}
                sx={{
                  backgroundColor: 'background.default',
                  '&:hover': { backgroundColor: 'grey.800' },
                }}
              >
                <TableCell component="th" scope="row" sx={{ color: 'text.primary' }}>
                  {user.username}
                </TableCell>
                {viewMode === 'profile' ? (
                  <>
                    <TableCell align="right" sx={{ color: 'text.primary' }}>
                      {user.totalSolved || 'N/A'}
                    </TableCell>
                    <TableCell align="right" sx={{ color: 'text.primary' }}>
                      {user.ranking || 'N/A'}
                    </TableCell>
                  </>
                ) : (
                  <TableCell align="right" sx={{ color: 'text.primary' }}>
                    {user.ranking !== Infinity ? user.ranking : 'N/A'}
                  </TableCell>
                )}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default LeetcodeLeaderboard;
